import { 
  Home, 
  Users, 
  UserCheck2,
  Calendar, 
  DollarSign, 
  Settings, 
  BookOpen,
  BarChart3,
  UserCheck,
  GraduationCap,
  Building2,
  CreditCard
} from "lucide-react";
import {
  Sidebar,
  SidebarContent,
  SidebarFooter,
  SidebarGroup,
  SidebarGroupContent,
  SidebarGroupLabel,
  SidebarHeader,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
} from "@/components/ui/sidebar";
import logoIcon from "@assets/Design sem nome (15)_1758779065313.png";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import { Link, useLocation } from "wouter";
import { useAuth } from "@/hooks/useAuth";
import { LogOut } from "lucide-react";

interface AppSidebarProps {
  userRole?: "SUPER_ADMIN" | "ADMIN_ACADEMIA" | "PROFESSOR" | "ALUNO";
  userInfo?: {
    name: string;
    email: string;
    academy: string;
    avatar?: string;
  };
}

export function AppSidebar({ 
  userRole = "ADMIN_ACADEMIA",
  userInfo = {
    name: userRole === "SUPER_ADMIN" ? "Super Admin" : "João Silva", 
    email: userRole === "SUPER_ADMIN" ? "admin@centrodelivtas.com" : "joao@academia.com", 
    academy: userRole === "SUPER_ADMIN" ? "Fight Club App Platform" : "Dragon Academy"
  }
}: AppSidebarProps) {
  const { logout } = useAuth();
  const [, setLocation] = useLocation();

  // Menu items based on user role
  const getMenuItems = () => {
    const baseItems = [
      {
        title: "Painel",
        url: "/dashboard",
        icon: Home,
        roles: ["ADMIN_ACADEMIA", "PROFESSOR", "ALUNO"]
      }
    ];

    // Super Admin specific items
    const superAdminItems = [
      {
        title: "Dashboard SA",
        url: "/superadmin/dashboard",
        icon: Home,
        roles: ["SUPER_ADMIN"]
      },
      {
        title: "Academias",
        url: "/superadmin/academias",
        icon: Building2,
        roles: ["SUPER_ADMIN"]
      },
      {
        title: "Planos",
        url: "/superadmin/planos",
        icon: CreditCard,
        roles: ["SUPER_ADMIN"]
      }
    ];

    const adminItems = [
      {
        title: "Alunos",
        url: "/dashboard/alunos",
        icon: Users,
        roles: ["ADMIN_ACADEMIA"]
      },
      {
        title: "Instrutores",
        url: "/dashboard/instrutores",
        icon: UserCheck2,
        roles: ["ADMIN_ACADEMIA"]
      },
      {
        title: "Planos e Matrículas",
        url: "/dashboard/planos",
        icon: CreditCard,
        roles: ["ADMIN_ACADEMIA"]
      },
      {
        title: "Grade de Aulas",
        url: "/dashboard/grade",
        icon: Calendar,
        roles: ["ADMIN_ACADEMIA", "PROFESSOR"]
      },
      {
        title: "Financeiro",
        url: "/dashboard/financeiro",
        icon: DollarSign,
        roles: ["ADMIN_ACADEMIA"]
      },
      {
        title: "Relatórios",
        url: "/reports",
        icon: BarChart3,
        roles: ["ADMIN_ACADEMIA"]
      },
      {
        title: "Configurações",
        url: "/settings",
        icon: Settings,
        roles: ["ADMIN_ACADEMIA"]
      }
    ];

    const studentItems = [
      {
        title: "Meus Horários",
        url: "/my-schedule",
        icon: Calendar,
        roles: ["ALUNO"]
      },
      {
        title: "Minha Presença",
        url: "/my-attendance",
        icon: BookOpen,
        roles: ["ALUNO"]
      },
      {
        title: "Meu Progresso",
        url: "/my-progress",
        icon: GraduationCap,
        roles: ["ALUNO"]
      },
      {
        title: "Perfil",
        url: "/profile",
        icon: Settings,
        roles: ["ALUNO", "PROFESSOR"]
      }
    ];

    return [...baseItems, ...superAdminItems, ...adminItems, ...studentItems].filter(item =>
      item.roles.includes(userRole)
    );
  };

  const menuItems = getMenuItems();

  // Remove handleMenuClick - we'll use Link components directly

  const getInitials = (name: string) => {
    return name.split(' ').map(n => n[0]).join('').toUpperCase();
  };

  const getRoleDisplay = (role: string) => {
    const roleMap = {
      "ADMIN_ACADEMIA": "Administrador",
      "PROFESSOR": "Professor",
      "ALUNO": "Aluno"
    };
    return roleMap[role as keyof typeof roleMap] || role;
  };

  return (
    <Sidebar>
      <SidebarHeader className="border-b border-sidebar-border">
        <div className="flex items-center space-x-2 p-2">
          <img src={logoIcon} alt="Fight Club App" className="h-8 w-8" />
          <div className="flex flex-col">
            <span className="font-bold text-sidebar-foreground">Fight Club App</span>
            <span className="text-xs text-sidebar-foreground/60">{userInfo.academy}</span>
          </div>
        </div>
      </SidebarHeader>

      <SidebarContent>
        <SidebarGroup>
          <SidebarGroupLabel>Navegação</SidebarGroupLabel>
          <SidebarGroupContent>
            <SidebarMenu>
              {menuItems.map((item) => (
                <SidebarMenuItem key={item.title}>
                  <SidebarMenuButton 
                    asChild
                    data-testid={`sidebar-${item.title.toLowerCase().replace(/\s+/g, '-')}`}
                  >
                    <Link href={item.url} className="w-full justify-start">
                      <item.icon className="mr-2 h-4 w-4" />
                      <span>{item.title}</span>
                    </Link>
                  </SidebarMenuButton>
                </SidebarMenuItem>
              ))}
            </SidebarMenu>
          </SidebarGroupContent>
        </SidebarGroup>
      </SidebarContent>

      <SidebarFooter className="border-t border-sidebar-border">
        <div className="p-4 space-y-3">
          <div className="flex items-center space-x-3">
            <Avatar className="h-10 w-10">
              <AvatarImage src={userInfo.avatar} alt={userInfo.name} />
              <AvatarFallback className="text-sm">
                {getInitials(userInfo.name)}
              </AvatarFallback>
            </Avatar>
            <div className="flex-1 min-w-0">
              <p className="text-sm font-medium text-sidebar-foreground truncate">
                {userInfo.name}
              </p>
              <p className="text-xs text-sidebar-foreground/60 truncate">
                {getRoleDisplay(userRole)}
              </p>
              <p className="text-xs text-sidebar-foreground/40 truncate">
                {userInfo.email}
              </p>
            </div>
          </div>

          {/* Logout Button */}
          <Button 
            variant="ghost" 
            size="sm"
            className="w-full justify-start text-sidebar-foreground/60 hover:text-sidebar-foreground"
            onClick={() => {
              logout();
              setLocation('/');
            }}
            data-testid="button-logout"
          >
            <LogOut className="mr-2 h-4 w-4" />
            Sair da Conta
          </Button>
        </div>
      </SidebarFooter>
    </Sidebar>
  );
}

client/src/components/AuthForms.tsx.content:
import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardFooter, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Eye, EyeOff, Shield } from "lucide-react";
import { SiGoogle } from "react-icons/si";
import { useAuth } from "@/hooks/useAuth";

interface LoginFormProps {
  onSuccess?: () => void;
}

interface SignupFormProps {
  onSuccess?: () => void;
}

export function LoginForm({ onSuccess }: LoginFormProps) {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [showPassword, setShowPassword] = useState(false);
  const { login, isLoggingIn } = useAuth();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    login({ email, password }, {
      onSuccess: () => {
        onSuccess?.();
      }
    });
  };

  return (
    <Card className="w-full max-w-md mx-auto">
      <form onSubmit={handleSubmit}>
        <CardContent className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="email">Email</Label>
            <Input
              id="email"
              type="email"
              placeholder="admin@academia.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
              data-testid="input-login-email"
            />
          </div>

          <div className="space-y-2">
            <Label htmlFor="password" className="password-label-spacing">Senha</Label>
            <div className="relative">
              <Input
                id="password"
                type={showPassword ? "text" : "password"}
                placeholder="Digite sua senha"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                required
                className="password-input-padding"
                data-testid="input-login-password"
              />
              <Button
                type="button"
                variant="ghost"
                size="icon"
                className="password-icon-position h-8 w-8"
                onClick={() => setShowPassword(!showPassword)}
                data-testid="button-toggle-password"
              >
                {showPassword ? <EyeOff className="h-4 w-4" /> : <Eye className="h-4 w-4" />}
              </Button>
            </div>
          </div>
        </CardContent>

        <CardFooter className="flex flex-col space-y-4">
          <Button 
            type="submit" 
            className="w-full" 
            disabled={isLoggingIn}
            data-testid="button-login-submit"
          >
            {isLoggingIn ? "Entrando..." : "Entrar"}
          </Button>

          <div className="text-sm text-center">
            <a href="#" className="text-primary hover:underline">
              Esqueceu sua senha?
            </a>
          </div>
        </CardFooter>
      </form>
    </Card>
  );
}

export function SignupForm({ onSuccess }: SignupFormProps) {
  const [formData, setFormData] = useState({
    email: "",
    password: "",
    confirmPassword: "",
    name: "",
    role: "",
    academyName: "",
  });
  const [showPassword, setShowPassword] = useState(false);
  const [passwordStrength, setPasswordStrength] = useState({ score: 0, text: "", color: "" });
  const { signup, isSigningUp } = useAuth();

  const calculatePasswordStrength = (password: string) => {
    if (!password) return { score: 0, text: "", color: "" };

    let score = 0;
    const checks = {
      length: password.length >= 8,
      lowercase: /[a-z]/.test(password),
      uppercase: /[A-Z]/.test(password),
      numbers: /\d/.test(password),
      special: /[!@#$%^&*(),.?":{}|<>]/.test(password)
    };

    // Calculate score based on criteria
    if (checks.length) score += 20;
    if (checks.lowercase) score += 20;
    if (checks.uppercase) score += 20;
    if (checks.numbers) score += 20;
    if (checks.special) score += 20;

    // Determine strength level
    if (score < 40) {
      return { score, text: "Muito fraca", color: "bg-red-500" };
    } else if (score < 60) {
      return { score, text: "Fraca", color: "bg-orange-500" };
    } else if (score < 80) {
      return { score, text: "Boa", color: "bg-yellow-500" };
    } else if (score < 100) {
      return { score, text: "Forte", color: "bg-green-500" };
    } else {
      return { score, text: "Muito forte", color: "bg-green-600" };
    }
  };

  const handleInputChange = (field: string, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));

    // Update password strength when password changes
    if (field === "password") {
      const strength = calculatePasswordStrength(value);
      setPasswordStrength(strength);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (formData.password !== formData.confirmPassword) {
      // This should show a proper error message
      return;
    }

    signup({
      name: formData.name,
      email: formData.email,
      password: formData.password,
      role: formData.role as 'ADMIN_ACADEMIA' | 'PROFESSOR' | 'ALUNO',
      academyName: formData.academyName || undefined
    }, {
      onSuccess: () => {
        onSuccess?.();
      }
    });
  };

  return (
    <Card className="w-full max-w-md mx-auto">
      <CardHeader className="text-center">
        <CardTitle className="text-2xl">Criar Conta</CardTitle>
      </CardHeader>

      <form onSubmit={handleSubmit}>
        <CardContent className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="signup-name">Nome Completo</Label>
            <Input
              id="signup-name"
              type="text"
              placeholder="João Silva"
              value={formData.name}
              onChange={(e) => handleInputChange("name", e.target.value)}
              required
              data-testid="input-signup-name"
            />
            <p className="error-message" data-testid="error-name"></p>
          </div>

          <div className="space-y-2">
            <Label htmlFor="signup-email">Email</Label>
            <Input
              id="signup-email"
              type="email"
              placeholder="admin@academia.com"
              value={formData.email}
              onChange={(e) => handleInputChange("email", e.target.value)}
              required
              data-testid="input-signup-email"
            />
