              <SelectContent>
                <SelectItem value="ADMIN_ACADEMIA">Administrador da Academia</SelectItem>
                <SelectItem value="PROFESSOR">Professor/Instrutor</SelectItem>
                <SelectItem value="ALUNO">Aluno</SelectItem>
              </SelectContent>
            </Select>
