                        <Mail className="h-4 w-4 text-muted-foreground" />
                        <span>{student.email}</span>
                      </div>
                    </TableCell>
                    <TableCell>
                      <div className="flex items-center space-x-2">
                        <Phone className="h-4 w-4 text-muted-foreground" />
                        <span>{formatPhone(student.phone)}</span>
                      </div>
                    </TableCell>
                    <TableCell>
                      {student.belt ? (
                        <Badge variant="secondary">{student.belt}</Badge>
                      ) : (
                        <span className="text-muted-foreground">-</span>
                      )}
                    </TableCell>
                    <TableCell>
                      <Badge variant={student.active ? "default" : "secondary"}>
                        {student.active ? "Ativo" : "Inativo"}
                      </Badge>
                    </TableCell>
                    <TableCell>
                      <div className="flex items-center space-x-2">
                        <Calendar className="h-4 w-4 text-muted-foreground" />
                        <span>{formatDate(student.createdAt)}</span>
                      </div>
                    </TableCell>
                    <TableCell className="text-right">
                      <DropdownMenu>
                        <DropdownMenuTrigger asChild>
                          <Button
                            size="sm"
                            variant="ghost"
                            data-testid={`button-student-actions-${student.id}`}
                          >
                            <MoreHorizontal className="h-4 w-4" />
                          </Button>
                        </DropdownMenuTrigger>
                        <DropdownMenuContent align="end">
                          <DropdownMenuItem 
                            onClick={(e) => {
                              try {
                                e.preventDefault();
                                e.stopPropagation();
                                console.log("View student details:", student);
                                console.log("About to call handleViewDetails...");
                                handleViewDetails(student);
                                console.log("handleViewDetails completed");
                              } catch (error) {
                                console.error("Error in View Details onClick:", error);
                              }
                            }}
                            data-testid={`button-view-student-${student.id}`}
                          >
                            <Eye className="h-4 w-4 mr-2" />
                            Ver Detalhes
                          </DropdownMenuItem>
                          <DropdownMenuItem 
                            onClick={(e) => {
                              e.preventDefault();
                              e.stopPropagation();
                              console.log("Edit student:", student);
                              handleEdit(student);
                            }}
                            data-testid={`button-edit-student-${student.id}`}
                          >
                            <Edit className="h-4 w-4 mr-2" />
                            Editar
                          </DropdownMenuItem>

                          {student.active ? (
                            <DropdownMenuItem 
                              onClick={(e) => {
                                e.preventDefault();
                                e.stopPropagation();
                                setDeleteStudent(student);
                              }}
                              className="text-destructive focus:text-destructive"
                              data-testid={`button-deactivate-student-${student.id}`}
                            >
                              <UserX className="h-4 w-4 mr-2" />
                              Desativar
                            </DropdownMenuItem>
                          ) : (
                            <DropdownMenuItem 
                              onClick={(e) => {
                                e.preventDefault();
                                e.stopPropagation();
                                setActivateStudent(student);
                              }}
                              className="text-green-600 focus:text-green-600"
                              data-testid={`button-activate-student-${student.id}`}
                            >
                              <UserCheck className="h-4 w-4 mr-2" />
                              Reativar
                            </DropdownMenuItem>
                          )}

                          <DropdownMenuItem 
                            onClick={(e) => {
                              e.preventDefault();
                              e.stopPropagation();
                              setPermanentDeleteStudent(student);
                            }}
                            className="text-destructive focus:text-destructive"
                            data-testid={`button-permanent-delete-student-${student.id}`}
                          >
                            <Trash2 className="h-4 w-4 mr-2" />
                            Excluir
                          </DropdownMenuItem>
                        </DropdownMenuContent>
                      </DropdownMenu>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

