import { test, expect } from '@playwright/test';
import { TestHelpers, TestAcademy, TestUser } from '../helpers/test-utils';

test.describe('Testes de Controle de Acesso por Papel (RBAC)', () => {
  let helpers: TestHelpers;
  let academy: TestAcademy;
  let professor: TestUser;
  let student: TestUser;

  test.beforeEach(async ({ page, request }) => {
    helpers = new TestHelpers(page, request);

    // Generate unique test data for this test run
    const testData = TestHelpers.generateTestData('RBAC');

    // Create academy with admin
    academy = await helpers.createTestAcademy(testData.academyA);

    // Create professor and student users
    professor = await helpers.createUser({
      name: `Professor RBAC ${Date.now()}`,
      email: `professor-rbac-${Date.now()}@test.com`,
      password: '123456',
      role: 'PROFESSOR'
    }, academy.admin.token!);

    student = await helpers.createUser({
      name: `Student RBAC ${Date.now()}`,
      email: `student-rbac-${Date.now()}@test.com`,
      password: '123456',
      role: 'ALUNO'
    }, academy.admin.token!);

    // Get actual tokens for professor and student via login
    professor.token = await helpers.loginUser(professor.email, professor.password);
    student.token = await helpers.loginUser(student.email, student.password);
  });

  test.afterEach(async () => {
    await helpers.cleanup();
  });

  test('Cenário 2.1: Professor NÃO deve conseguir criar novos alunos', async () => {
    // Try to create student as professor (should fail with 403 - forbidden)
    const createStudentResult = await helpers.apiRequest(
      'POST',
      '/students',
      professor.token!, // Now using real professor token
      {
        name: 'Unauthorized Student',
        email: `unauthorized-${Date.now()}@test.com`,
        password: '123456', // Include required password field
        role: 'ALUNO'
      }
    );

    // Should fail with 403 (forbidden) - professor authenticated but lacks permission
    expect(createStudentResult.ok).toBe(false);
    expect(createStudentResult.status).toBe(403);
  });

  test('Cenário 2.2: Professor PODE ler classes mas NÃO pode criar class types', async () => {
    // Professor should be able to read classes (they need this for teaching)
    const readClassesResult = await helpers.apiRequest(
      'GET',
      '/classes',
      professor.token!
    );

    expect(readClassesResult.ok).toBe(true);
    expect(readClassesResult.status).toBe(200);

    // But should NOT be able to create class types (admin-only)
    const createClassTypeResult = await helpers.apiRequest(
      'POST',
      '/class-types',
      professor.token!,
      {
        name: 'Unauthorized Class Type',
        description: 'Should not be created',
        duration: 60
      }
    );

    expect(createClassTypeResult.ok).toBe(false);
    expect(createClassTypeResult.status).toBe(403);
  });

  test('Cenário 2.3: Aluno NÃO deve ter acesso a endpoints administrativos', async () => {
    // Test various admin endpoints that students should not access
    const adminOnlyEndpoints = [
      '/students',     // Student management is admin-only
      '/instructors',  // Instructor management is admin-only
      '/class-types'   // Class type management is admin-only
    ];

    for (const endpoint of adminOnlyEndpoints) {
      const result = await helpers.apiRequest('GET', endpoint, student.token!);

      // Should fail with 403 (forbidden) - student authenticated but lacks permission
      expect(result.ok).toBe(false);
      expect(result.status).toBe(403);
    }

    // But students should be able to see class schedule
    const classesResult = await helpers.apiRequest('GET', '/classes', student.token!);
    expect(classesResult.ok).toBe(true);
    expect(classesResult.status).toBe(200);
  });

  test('Cenário 2.4: Admin deve ter acesso completo a todos os recursos', async () => {
    // Test that admin can access all endpoints
    const adminEndpoints = [
      '/students',
      '/instructors', 
      '/class-types',
      '/classes'
    ];

    for (const endpoint of adminEndpoints) {
      const result = await helpers.apiRequest('GET', endpoint, academy.admin.token!);

      // Admin should have access to all endpoints
      expect(result.ok).toBe(true);
      expect(result.status).toBe(200);
    }
  });

  test('Cenário 2.5: Admin pode criar e gerenciar todos os tipos de usuário', async () => {
    // Create student with complete payload
    const newStudent = await helpers.apiRequest(
      'POST',
      '/students',
      academy.admin.token!,
      {
        name: `Admin Created Student ${Date.now()}`,
        email: `admin-student-${Date.now()}@test.com`,
        password: '123456',
        role: 'ALUNO'
      }
    );

    expect(newStudent.ok).toBe(true);
    expect(newStudent.data.role).toBe('ALUNO');

    // Create instructor using correct endpoint
    const newInstructor = await helpers.apiRequest(
      'POST',
      '/instructors',
      academy.admin.token!,
      {
        name: `Admin Created Instructor ${Date.now()}`,
        email: `admin-instructor-${Date.now()}@test.com`,
        password: '123456',
        role: 'PROFESSOR'
      }
    );

    expect(newInstructor.ok).toBe(true);
    expect(newInstructor.data.role).toBe('PROFESSOR');

    // Verify they appear in respective lists
    const students = await helpers.apiRequest('GET', '/students', academy.admin.token!);
    const instructors = await helpers.apiRequest('GET', '/instructors', academy.admin.token!);

    expect(students.data.some((s: any) => s.email === newStudent.data.email)).toBe(true);
    expect(instructors.data.some((i: any) => i.email === newInstructor.data.email)).toBe(true);
  });

  test('Cenário 2.6: Admin pode criar class types e classes completas', async () => {
    // Create class type
    const classType = await helpers.apiRequest(
      'POST',
      '/class-types',
      academy.admin.token!,
      {
        name: `Admin Class Type ${Date.now()}`,
        description: 'Class type created by admin',
        duration: 60
      }
    );

    expect(classType.ok).toBe(true);

    // Create instructor for the class
    const instructor = await helpers.apiRequest(
      'POST',
      '/instructors',
      academy.admin.token!,
      {
        name: `Class Instructor ${Date.now()}`,
        email: `class-instructor-${Date.now()}@test.com`,
        password: '123456',
        role: 'PROFESSOR'
      }
    );

    expect(instructor.ok).toBe(true);

    // Create class
    const newClass = await helpers.apiRequest(
      'POST',
      '/classes',
      academy.admin.token!,
      {
        classTypeId: classType.data.id,
        instructorId: instructor.data.id,
        dayOfWeek: 2, // Tuesday
        startTime: '19:00',
        endTime: '20:30'
      }
    );

    expect(newClass.ok).toBe(true);
    expect(newClass.data.dayOfWeek).toBe(2);

    // Verify class appears in classes list
    const classes = await helpers.apiRequest('GET', '/classes', academy.admin.token!);
    expect(classes.data.some((c: any) => c.id === newClass.data.id)).toBe(true);
  });

  test('Cenário 2.7: Verificação de tokens inválidos ou expirados', async () => {
    const invalidToken = 'invalid-token-12345';

    // Test with invalid token
    const result = await helpers.apiRequest('GET', '/students', invalidToken);

    expect(result.ok).toBe(false);
    expect(result.status).toBe(401);
  });

  test('Cenário 2.8: Verificação de requisições sem token', async () => {
    // Test without token
    const result = await helpers.apiRequest('GET', '/students', '');

    expect(result.ok).toBe(false);
    expect(result.status).toBe(401);
  });
});

tests/e2e/03-main-user-flows.spec.ts.content:
import { test, expect } from '@playwright/test';
import { TestHelpers, TestAcademy } from '../helpers/test-utils';

test.describe('Fluxos Principais da Aplicação', () => {
  let helpers: TestHelpers;
  let academy: TestAcademy;

  test.beforeEach(async ({ page, request }) => {
    helpers = new TestHelpers(page, request);
  });

  test.afterEach(async () => {
    await helpers.cleanup();
  });

  test('Fluxo 3.1: Cadastro completo de academia e primeiro acesso ao dashboard', async ({ page }) => {
    const testData = TestHelpers.generateTestData('FLOW');

    // Navigate to homepage
    await page.goto('/');
    await expect(page).toHaveTitle(/Centro de Lutas/);

    // Access signup page
    await page.click('[data-testid="link-signup"]');
    await expect(page).toHaveURL('/cadastro');

    // Fill signup form
    await page.fill('[data-testid="input-name"]', testData.academyA.admin.name);
    await page.fill('[data-testid="input-email"]', testData.academyA.admin.email);
    await page.fill('[data-testid="input-password"]', testData.academyA.admin.password);
    await page.fill('[data-testid="input-academy-name"]', testData.academyA.name);

    // Submit signup
    await page.click('[data-testid="button-signup"]');

    // Should redirect to dashboard
    await expect(page).toHaveURL('/dashboard');

    // Dashboard should show welcome information
    await expect(page.locator('h1')).toContainText('Painel da Academia');

    // Check if navigation items are visible
    await expect(page.locator('[data-testid="nav-alunos"]')).toBeVisible();
    await expect(page.locator('[data-testid="nav-aulas"]')).toBeVisible();
  });

  test('Fluxo 3.2: Ciclo completo de gerenciamento de alunos', async ({ page }) => {
    // Setup academy
    const testData = TestHelpers.generateTestData('STUDENTS');
    academy = await helpers.createTestAcademy(testData.academyA);

    // Navigate to student management
    await page.goto('/dashboard/alunos');
    await expect(page.locator('h1')).toContainText('Gerenciamento de Alunos');

    // Add new student
    await page.click('[data-testid="button-add-student"]');

    // Fill student form
    const studentName = `Test Student ${Date.now()}`;
    const studentEmail = `student-${Date.now()}@test.com`;

    await page.fill('[data-testid="input-name"]', studentName);
    await page.fill('[data-testid="input-email"]', studentEmail);
    await page.fill('[data-testid="input-phone"]', '(11) 99999-9999');

    // Submit form
    await page.click('[data-testid="button-submit"]');

    // Should show success message
    await expect(page.locator('.toast')).toContainText('cadastrado com sucesso');

    // Student should appear in the list
    await expect(page.locator(`text=${studentName}`)).toBeVisible();
    await expect(page.locator(`text=${studentEmail}`)).toBeVisible();

    // Test search functionality
    await page.fill('[data-testid="input-search"]', studentName);
    await expect(page.locator(`text=${studentName}`)).toBeVisible();

    // Clear search
    await page.fill('[data-testid="input-search"]', '');
  });

  test('Fluxo 3.3: Criação de modalidades e agendamento de aulas', async ({ page }) => {
    // Setup academy
    const testData = TestHelpers.generateTestData('CLASSES');
    academy = await helpers.createTestAcademy(testData.academyA);

    // Create instructor first via API
    const instructor = await helpers.createUser({
      name: `Professor Test ${Date.now()}`,
      email: `professor-${Date.now()}@test.com`,
      password: '123456',
      role: 'PROFESSOR'
    }, academy.admin.token!);

    // Navigate to class management
    await page.goto('/dashboard/aulas');

    // Test creating class type first
    await page.click('[data-testid="tab-modalidades"]');
    await page.click('[data-testid="button-add-modality"]');

    const modalityName = `Muay Thai ${Date.now()}`;
    await page.fill('[data-testid="input-name"]', modalityName);
    await page.fill('[data-testid="input-description"]', 'Arte marcial tailandesa');
    await page.fill('[data-testid="input-duration"]', '60');

    await page.click('[data-testid="button-submit"]');

    // Should show success message
    await expect(page.locator('.toast')).toContainText('criada com sucesso');

    // Now create a class
    await page.click('[data-testid="tab-cronograma"]');
    await page.click('[data-testid="button-schedule-class"]');

    // Fill class form
    await page.click('[data-testid="select-modality"]');
    await page.click(`text=${modalityName}`);

    await page.click('[data-testid="select-instructor"]');
    await page.click(`text=${instructor.name}`);

    await page.selectOption('[data-testid="select-day"]', '1'); // Monday
    await page.fill('[data-testid="input-start-time"]', '18:00');
    await page.fill('[data-testid="input-end-time"]', '19:00');

    await page.click('[data-testid="button-submit"]');

    // Should show success message
    await expect(page.locator('.toast')).toContainText('criada com sucesso');

    // Class should appear in schedule
    await expect(page.locator('text=18:00')).toBeVisible();
  });

  test('Fluxo 3.4: Visualização da grade horária semanal', async ({ page }) => {
    // Setup academy with class
    const testData = TestHelpers.generateTestData('SCHEDULE');
    academy = await helpers.createTestAcademy(testData.academyA);

    // Create class type and instructor via API for faster setup
    const classTypeResult = await helpers.apiRequest(
      'POST',
      '/class-types',
      academy.admin.token!,
      {
        name: `BJJ Schedule ${Date.now()}`,
        description: 'Brazilian Jiu-Jitsu',
        duration: 90
      }
    );

    const instructor = await helpers.createUser({
      name: `Schedule Prof ${Date.now()}`,
      email: `schedule-prof-${Date.now()}@test.com`,
      password: '123456',
      role: 'PROFESSOR'
    }, academy.admin.token!);

    // Create multiple classes for schedule visualization
    const classesData = [
      { day: 1, start: '08:00', end: '09:30' }, // Monday morning
      { day: 1, start: '18:00', end: '19:30' }, // Monday evening
      { day: 3, start: '19:00', end: '20:30' }, // Wednesday evening
      { day: 5, start: '07:00', end: '08:30' }, // Friday morning
    ];

    for (const classData of classesData) {
      await helpers.apiRequest(
        'POST',
        '/classes',
        academy.admin.token!,
        {
          classTypeId: classTypeResult.data.id,
          instructorId: instructor.id,
          dayOfWeek: classData.day,
          startTime: classData.start,
          endTime: classData.end
        }
      );
    }

    // Navigate to schedule
    await page.goto('/dashboard/grade');

    // Should show weekly schedule grid
    await expect(page.locator('h1')).toContainText('Grade Horária');

    // Check for days of week
    await expect(page.locator('text=Segunda-feira')).toBeVisible();
    await expect(page.locator('text=Quarta-feira')).toBeVisible();
    await expect(page.locator('text=Sexta-feira')).toBeVisible();

    // Check for class times
    await expect(page.locator('text=08:00')).toBeVisible();
    await expect(page.locator('text=18:00')).toBeVisible();
    await expect(page.locator('text=19:00')).toBeVisible();

    // Check for class information
    await expect(page.locator(`text=${classTypeResult.data.name}`)).toBeVisible();
    await expect(page.locator(`text=${instructor.name}`)).toBeVisible();
  });

  test('Fluxo 3.5: Login e logout de usuário existente', async ({ page }) => {
    // Setup academy
    const testData = TestHelpers.generateTestData('LOGIN');
    academy = await helpers.createTestAcademy(testData.academyA);

    // Logout
    await helpers.cleanup();

    // Go to login page
    await page.goto('/login');

    // Fill login form
    await page.fill('[data-testid="input-email"]', academy.admin.email);
    await page.fill('[data-testid="input-password"]', academy.admin.password);

    // Submit login
    await page.click('[data-testid="button-login"]');

    // Should redirect to dashboard
    await expect(page).toHaveURL('/dashboard');
    await expect(page.locator('h1')).toContainText('Painel da Academia');

    // Test logout
    await page.click('[data-testid="user-menu"]');
    await page.click('[data-testid="button-logout"]');

    // Should redirect to homepage
    await expect(page).toHaveURL('/');
  });

  test('Fluxo 3.6: Validação de formulários e tratamento de erros', async ({ page }) => {
    // Navigate to signup with invalid data
    await page.goto('/cadastro');

    // Try to submit empty form
    await page.click('[data-testid="button-signup"]');

    // Should show validation errors
    const errorElements = page.locator('.error, .text-destructive');
    await expect(errorElements.first()).toBeVisible();

    // Test invalid email format
    await page.fill('[data-testid="input-name"]', 'Test User');
    await page.fill('[data-testid="input-email"]', 'invalid-email');
    await page.fill('[data-testid="input-password"]', '123');
    await page.fill('[data-testid="input-academy-name"]', 'Test Academy');

    await page.click('[data-testid="button-signup"]');

    // Should show email validation error
    await expect(page.locator('text=email')).toBeVisible();
  });

  test('Fluxo 3.7: Responsividade em dispositivos móveis', async ({ page }) => {
    // Set mobile viewport
    await page.setViewportSize({ width: 375, height: 667 });

    const testData = TestHelpers.generateTestData('MOBILE');
    academy = await helpers.createTestAcademy(testData.academyA);

    // Test navigation on mobile
    await page.goto('/dashboard');

    // Should have mobile-friendly navigation
    await expect(page.locator('[data-testid="nav-alunos"]')).toBeVisible();

    // Test student management on mobile
    await page.goto('/dashboard/alunos');
    await expect(page.locator('h1')).toContainText('Gerenciamento de Alunos');

    // Forms should be mobile-friendly
    await page.click('[data-testid="button-add-student"]');
    await expect(page.locator('[data-testid="input-name"]')).toBeVisible();
  });
});

