import { test, expect } from '@playwright/test';
import { TestHelpers, TestAcademy, TestUser } from '../helpers/test-utils';

test.describe('Testes de Performance e Integração', () => {
  let helpers: TestHelpers;
  let academy: TestAcademy;

  test.beforeEach(async ({ page, request }) => {
    helpers = new TestHelpers(page, request);
  });

  test.afterEach(async () => {
    await helpers.cleanup();
  });

  test('Performance 4.1: Carregamento rápido do dashboard', async ({ page }) => {
    const testData = TestHelpers.generateTestData('PERF');
    academy = await helpers.createTestAcademy(testData.academyA);

    const startTime = Date.now();

    // Navigate to dashboard
    await page.goto('/dashboard');

    // Wait for main content to load
    await expect(page.locator('h1')).toContainText('Painel da Academia');

    const loadTime = Date.now() - startTime;

    // Dashboard should load within 3 seconds
    expect(loadTime).toBeLessThan(3000);

    // Check that key metrics are visible
    await expect(page.locator('[data-testid="metric-students"]')).toBeVisible();
    await expect(page.locator('[data-testid="metric-classes"]')).toBeVisible();
  });

  test('Performance 4.2: Lista de alunos com muitos registros', async ({ page }) => {
    const testData = TestHelpers.generateTestData('PERF-STUDENTS');
    academy = await helpers.createTestAcademy(testData.academyA);

    // Create multiple students via API for performance testing
    const studentPromises: Promise<TestUser>[] = [];
    for (let i = 0; i < 20; i++) {
      studentPromises.push(
        helpers.createUser({
          name: `Performance Student ${i + 1}`,
          email: `perf-student-${i + 1}-${Date.now()}@test.com`,
          password: '123456',
          role: 'ALUNO'
        }, academy.admin.token!)
      );
    }

    await Promise.all(studentPromises);

    const startTime = Date.now();

    // Navigate to students page
    await page.goto('/dashboard/alunos');

    // Wait for students list to load
    await expect(page.locator('[data-testid="students-table"]')).toBeVisible();

    const loadTime = Date.now() - startTime;

    // Students page should load within 5 seconds even with many records
    expect(loadTime).toBeLessThan(5000);

    // Check that students are displayed
    const studentRows = page.locator('[data-testid*="student-row"]');
    await expect(studentRows.first()).toBeVisible();
  });

  test('Integration 4.3: API consistency - Front-end e back-end sincronizados', async ({ page }) => {
    const testData = TestHelpers.generateTestData('INTEGRATION');
    academy = await helpers.createTestAcademy(testData.academyA);

    // Create student via API
    const apiStudent = await helpers.createUser({
      name: `API Integration Student ${Date.now()}`,
      email: `api-integration-${Date.now()}@test.com`,
      password: '123456',
      role: 'ALUNO'
    }, academy.admin.token!);

    // Verify student appears in UI
    await page.goto('/dashboard/alunos');

    // Should see the student created via API
    await expect(page.locator(`text=${apiStudent.name}`)).toBeVisible();
    await expect(page.locator(`text=${apiStudent.email}`)).toBeVisible();

    // Create student via UI
    await page.click('[data-testid="button-add-student"]');

    const uiStudentName = `UI Integration Student ${Date.now()}`;
    const uiStudentEmail = `ui-integration-${Date.now()}@test.com`;

    await page.fill('[data-testid="input-name"]', uiStudentName);
    await page.fill('[data-testid="input-email"]', uiStudentEmail);
    await page.click('[data-testid="button-submit"]');

    // Verify student appears in API
    const studentsFromAPI = await helpers.apiRequest('GET', '/students', academy.admin.token!);
    expect(studentsFromAPI.ok).toBe(true);

    const uiStudentInAPI = studentsFromAPI.data.find((s: any) => s.email === uiStudentEmail);
    expect(uiStudentInAPI).toBeDefined();
    expect(uiStudentInAPI.name).toBe(uiStudentName);
  });

  test('Integration 4.4: Cache invalidation - Mudanças refletem imediatamente', async ({ page }) => {
    const testData = TestHelpers.generateTestData('CACHE');
    academy = await helpers.createTestAcademy(testData.academyA);

    // Navigate to students page
    await page.goto('/dashboard/alunos');

    // Initial state should have no students
    await expect(page.locator('text=Nenhum aluno cadastrado')).toBeVisible();

    // Create student via API while page is open
    const newStudent = await helpers.createUser({
      name: `Cache Test Student ${Date.now()}`,
      email: `cache-test-${Date.now()}@test.com`,
      password: '123456',
      role: 'ALUNO'
    }, academy.admin.token!);

    // Refresh page to check if cache is invalidated
    await page.reload();

    // Student should appear immediately after refresh
    await expect(page.locator(`text=${newStudent.name}`)).toBeVisible();
  });

  test('Integration 4.5: Fluxo completo de gerenciamento de aulas', async ({ page }) => {
    const testData = TestHelpers.generateTestData('CLASS-FLOW');
    academy = await helpers.createTestAcademy(testData.academyA);

    // Step 1: Create instructor via API
    const instructor = await helpers.createUser({
      name: `Flow Instructor ${Date.now()}`,
      email: `flow-instructor-${Date.now()}@test.com`,
      password: '123456',
      role: 'PROFESSOR'
    }, academy.admin.token!);

    // Step 2: Create class type via UI
    await page.goto('/dashboard/aulas');
    await page.click('[data-testid="tab-modalidades"]');
    await page.click('[data-testid="button-add-modality"]');

    const modalityName = `Flow Muay Thai ${Date.now()}`;
    await page.fill('[data-testid="input-name"]', modalityName);
    await page.fill('[data-testid="input-description"]', 'End-to-end test modality');
    await page.fill('[data-testid="input-duration"]', '75');
    await page.click('[data-testid="button-submit"]');

    // Step 3: Create class using the modality and instructor
    await page.click('[data-testid="tab-cronograma"]');
    await page.click('[data-testid="button-schedule-class"]');

    await page.click('[data-testid="select-modality"]');
    await page.click(`text=${modalityName}`);

    await page.click('[data-testid="select-instructor"]');
    await page.click(`text=${instructor.name}`);

    await page.selectOption('[data-testid="select-day"]', '2'); // Tuesday
    await page.fill('[data-testid="input-start-time"]', '20:00');
    await page.fill('[data-testid="input-end-time"]', '21:15');
    await page.click('[data-testid="button-submit"]');

    // Step 4: Verify class appears in schedule
    await page.goto('/dashboard/grade');

    await expect(page.locator('text=20:00')).toBeVisible();
    await expect(page.locator(`text=${modalityName}`)).toBeVisible();
    await expect(page.locator(`text=${instructor.name}`)).toBeVisible();

    // Step 5: Verify via API that everything is consistent
    const classesFromAPI = await helpers.apiRequest('GET', '/classes', academy.admin.token!);
    expect(classesFromAPI.ok).toBe(true);
    expect(classesFromAPI.data.length).toBeGreaterThan(0);

    const createdClass = classesFromAPI.data.find((c: any) => 
      c.startTime === '20:00' && c.dayOfWeek === 2
    );
    expect(createdClass).toBeDefined();
  });

  test('Error Handling 4.6: Tratamento de erros de conectividade', async ({ page }) => {
    const testData = TestHelpers.generateTestData('ERROR');
    academy = await helpers.createTestAcademy(testData.academyA);

    // Navigate to students page
    await page.goto('/dashboard/alunos');

    // Simulate network failure by intercepting requests
    await page.route('**/api/students', route => {
      route.abort();
    });

    // Try to add student - should handle error gracefully
    await page.click('[data-testid="button-add-student"]');
    await page.fill('[data-testid="input-name"]', 'Error Test Student');
    await page.fill('[data-testid="input-email"]', 'error-test@test.com');
    await page.click('[data-testid="button-submit"]');

    // Should show error message
    await expect(page.locator('.toast')).toContainText('erro');
  });

  test('Security 4.7: Proteção contra ataques XSS', async ({ page }) => {
    const testData = TestHelpers.generateTestData('XSS');
    academy = await helpers.createTestAcademy(testData.academyA);

    // Try to inject script in student name
    await page.goto('/dashboard/alunos');
    await page.click('[data-testid="button-add-student"]');

    const maliciousName = '<script>alert("XSS")</script>';

    await page.fill('[data-testid="input-name"]', maliciousName);
    await page.fill('[data-testid="input-email"]', 'xss-test@test.com');
    await page.click('[data-testid="button-submit"]');

    // Script should not execute - content should be escaped
    await expect(page.locator('text=<script>')).toBeVisible(); // Should show as text, not execute

    // No alert should have been shown
    expect(page.locator('role=alert')).toHaveCount(0);
  });

  test('Accessibility 4.8: Navegação por teclado e leitores de tela', async ({ page }) => {
    const testData = TestHelpers.generateTestData('A11Y');
    academy = await helpers.createTestAcademy(testData.academyA);

    await page.goto('/dashboard');

    // Test keyboard navigation
    await page.keyboard.press('Tab'); // Should focus first navigable element
    await page.keyboard.press('Enter'); // Should activate focused element

    // Check for proper ARIA labels
    const navItems = page.locator('[role="navigation"] a');
    for (const item of await navItems.all()) {
      const ariaLabel = await item.getAttribute('aria-label');
      const textContent = await item.textContent();

      // Should have either aria-label or meaningful text content
      expect(ariaLabel || textContent?.trim()).toBeTruthy();
    }

    // Check form labels
    await page.goto('/dashboard/alunos');
    await page.click('[data-testid="button-add-student"]');

    const inputs = page.locator('input');
    for (const input of await inputs.all()) {
      const id = await input.getAttribute('id');
      if (id) {
        const label = page.locator(`label[for="${id}"]`);
        await expect(label).toBeVisible();
      }
    }
  });
});

tests/helpers/test-utils.ts.content:
import { Page, expect } from '@playwright/test';
import { APIRequestContext } from '@playwright/test';

export interface TestUser {
  id?: string;
  name: string;
  email: string;
  password: string;
  role: 'ADMIN_ACADEMIA' | 'PROFESSOR' | 'ALUNO';
  academyName?: string;
  token?: string;
  createdByAdminToken?: string; // Track which admin token was used to create this user
}

export interface TestAcademy {
  id?: string;
  name: string;
  slug?: string;
  admin: TestUser;
}

export class TestHelpers {
  private createdAcademies: TestAcademy[] = [];
  private createdUsers: TestUser[] = [];

  constructor(
    private page: Page,
    private request: APIRequestContext
  ) {}

  /**
   * Creates a test academy with admin user via signup
   */
  async createTestAcademy(academyData: TestAcademy): Promise<TestAcademy> {
    // Navigate to signup page
    await this.page.goto('/');
    await this.page.click('[data-testid="link-signup"]');

    // Fill signup form
    await this.page.fill('[data-testid="input-name"]', academyData.admin.name);
    await this.page.fill('[data-testid="input-email"]', academyData.admin.email);
    await this.page.fill('[data-testid="input-password"]', academyData.admin.password);
    await this.page.fill('[data-testid="input-academy-name"]', academyData.name);

    // Submit signup
    await this.page.click('[data-testid="button-signup"]');

    // Wait for redirect to dashboard
    await this.page.waitForURL('/dashboard', { timeout: 10000 });

    // Extract auth token from localStorage
    const token = await this.page.evaluate(() => localStorage.getItem('auth_token'));

    if (!token) {
      throw new Error('Failed to get auth token after signup');
    }

    academyData.admin.token = token;

    // Track for cleanup
    this.createdAcademies.push(academyData);

    return academyData;
  }

  /**
   * Creates a user (student or instructor) via API
   */
  async createUser(userData: Omit<TestUser, 'token'>, adminToken: string): Promise<TestUser> {
    const endpoint = userData.role === 'PROFESSOR' ? '/api/instructors' : '/api/students';

    const response = await this.request.post(endpoint, {
      headers: {
        'Authorization': `Bearer ${adminToken}`,
        'Content-Type': 'application/json',
      },
      data: {
        name: userData.name,
        email: userData.email,
        password: userData.password,
        role: userData.role,
      },
    });

    if (!response.ok()) {
      const error = await response.text();
      throw new Error(`Failed to create user: ${error}`);
    }

    const createdUser = await response.json();
    const userWithToken = {
      ...userData,
      id: createdUser.id,
      createdByAdminToken: adminToken, // Store the admin token used to create this user
    };

    // Track for cleanup
    this.createdUsers.push(userWithToken);

    return userWithToken;
  }

  /**
   * Logs in a user and returns their JWT token
   */
  async loginUser(email: string, password: string): Promise<string> {
    const response = await this.request.post('/api/auth/login', {
      headers: {
        'Content-Type': 'application/json',
      },
      data: {
        email,
        password,
      },
    });

    if (!response.ok()) {
      const error = await response.text();
      throw new Error(`Failed to login user ${email}: ${error}`);
    }

    const loginData = await response.json();
    return loginData.token;
  }

  /**
   * Authenticates with stored credentials
   */
  async authenticate(token: string): Promise<void> {
    await this.page.evaluate((authToken) => {
      localStorage.setItem('auth_token', authToken);
    }, token);
  }

  /**
   * Makes an authenticated API request
   */
  async apiRequest(
    method: string,
    endpoint: string,
    token: string,
    data?: any
  ): Promise<any> {
    const response = await this.request.fetch(`/api${endpoint}`, {
      method,
      headers: {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/json',
      },
      data: data ? JSON.stringify(data) : undefined,
    });

    return {
      status: response.status(),
      ok: response.ok(),
      data: response.ok() ? await response.json().catch(() => null) : null,
      error: !response.ok() ? await response.text() : null,
    };
  }

  /**
   * Cleans up test data by logging out and clearing created resources
   */
  async cleanup(): Promise<void> {
    // Clear browser storage
    await this.page.evaluate(() => {
      localStorage.clear();
      sessionStorage.clear();
    });

    // Cleanup created users using their specific admin tokens
    for (const user of this.createdUsers) {
      try {
        if (user.id && user.createdByAdminToken) {
          const endpoint = user.role === 'PROFESSOR' ? '/instructors' : '/students';
          await this.request.delete(`/api${endpoint}/${user.id}`, {
            headers: {
              'Authorization': `Bearer ${user.createdByAdminToken}`,
            },
          });
        }
      } catch (error) {
        console.warn(`Failed to cleanup user ${user.email}:`, error);
      }
    }
    this.createdUsers = [];

    // Note: Academy cleanup is complex due to foreign key constraints
    // In a real implementation, we'd need proper cascade deletion or a test-only cleanup endpoint
    this.createdAcademies = [];
  }

  /**
   * Generates unique test data
   */
  static generateTestData(prefix: string) {
    const timestamp = Date.now();
    return {
      academyA: {
        name: `${prefix} Academia A ${timestamp}`,
        admin: {
          name: `Admin A ${timestamp}`,
          email: `admin-a-${timestamp}@test.com`,
          password: '123456',
          role: 'ADMIN_ACADEMIA' as const,
        },
      },
      academyB: {
        name: `${prefix} Academia B ${timestamp}`,
        admin: {
          name: `Admin B ${timestamp}`,
          email: `admin-b-${timestamp}@test.com`,
          password: '123456',
          role: 'ADMIN_ACADEMIA' as const,
        },
      },
    };
  }
}

client/src/pages/PortalDashboard.tsx.content:
import { useQuery } from "@tanstack/react-query";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { Button } from "@/components/ui/button";
import { Skeleton } from "@/components/ui/skeleton";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { 
  Calendar, 
  Clock, 
  TrendingUp, 
  Award, 
  Users, 
  CheckCircle2, 
  LogOut,
  CalendarDays,
  AlertCircle 
} from "lucide-react";
import { useAuth } from "@/hooks/useAuth";
import { useLocation } from "wouter";
import { apiClient } from "@/lib/api";

interface StudentData {
  enrollments: Array<{
    id: string;
    membershipPlan: {
      name: string;
      price: number;
      classesPerWeek: number;
    };
    class: {
      classType: {
        name: string;
        duration: number;
      };
      instructor: {
        name: string;
      };
      dayOfWeek: number;
      startTime: string;
      endTime: string;
    };
    startDate: string;
    endDate?: string;
    active: boolean;
  }>;
  attendance: Array<{
    id: string;
    date: string;
    status: string;
    notes?: string;
    class: {
      classType: {
        name: string;
      };
      instructor: {
        name: string;
      };
    };
  }>;
  payments: Array<{
    id: string;
    amount: number;
    dueDate: string;
    paidDate?: string;
    status: string;
    membershipPlan: {
      name: string;
    };
  }>;
}

export default function PortalDashboard() {
  const { user, logout } = useAuth();
  const [, setLocation] = useLocation();

  const { data: studentData, isLoading, error } = useQuery<StudentData>({
    queryKey: ['/api/student/me'],
    enabled: !!user && user.role === 'ALUNO',
  });

  const handleLogout = () => {
    logout();
    setLocation("/portal/login");
  };

  const navigateToSchedule = () => {
    setLocation("/portal/horarios");
  };

  // Calculate stats
  const stats = studentData ? calculateStats(studentData) : null;

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background">
        <PortalHeader user={user} onLogout={handleLogout} />
        <main className="container max-w-6xl mx-auto p-6">
          <div className="space-y-6">
            <SkeletonLoader />
          </div>
        </main>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-background">
        <PortalHeader user={user} onLogout={handleLogout} />
        <main className="container max-w-6xl mx-auto p-6">
          <Alert variant="destructive">
            <AlertCircle className="h-4 w-4" />
            <AlertDescription>
              Erro ao carregar dados do portal. Tente novamente mais tarde.
            </AlertDescription>
          </Alert>
        </main>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-background">
      <PortalHeader user={user} onLogout={handleLogout} />

      <main className="container max-w-6xl mx-auto p-6">
        <div className="space-y-6">
          {/* Welcome Section */}
          <div>
            <h1 className="text-3xl font-bold text-foreground">
              Bem-vindo de volta, {user?.name}!
            </h1>
            <p className="text-muted-foreground mt-2">
              Aqui está seu resumo de treinos e próximas aulas.
            </p>
          </div>

          {/* Quick Actions */}
          <div className="flex flex-wrap gap-3">
            <Button onClick={navigateToSchedule} data-testid="button-view-schedule">
              <CalendarDays className="mr-2 h-4 w-4" />
              Ver Grade de Horários
            </Button>
          </div>

          {/* Stats Overview */}
          {stats && (
            <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
              <Card>
                <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                  <CardTitle className="text-sm font-medium">Taxa de Presença</CardTitle>
                  <TrendingUp className="h-4 w-4 text-muted-foreground" />
                </CardHeader>
                <CardContent>
                  <div className="text-2xl font-bold" data-testid="stat-attendance-rate">
                    {stats.attendanceRate.toFixed(0)}%
                  </div>
                  <Progress value={stats.attendanceRate} className="mt-2" />
                </CardContent>
              </Card>

              <Card>
                <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                  <CardTitle className="text-sm font-medium">Aulas Frequentadas</CardTitle>
                  <Users className="h-4 w-4 text-muted-foreground" />
                </CardHeader>
                <CardContent>
                  <div className="text-2xl font-bold" data-testid="stat-classes-attended">
                    {stats.classesAttended}
                  </div>
                  <p className="text-xs text-muted-foreground mt-1">
                    de {stats.totalClasses} este mês
                  </p>
                </CardContent>
              </Card>

              <Card>
                <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                  <CardTitle className="text-sm font-medium">Sequência Atual</CardTitle>
                  <Award className="h-4 w-4 text-muted-foreground" />
                </CardHeader>
                <CardContent>
                  <div className="text-2xl font-bold" data-testid="stat-current-streak">
                    {stats.currentStreak}
                  </div>
                  <p className="text-xs text-muted-foreground mt-1">
                    aulas consecutivas
                  </p>
                </CardContent>
              </Card>

              <Card>
                <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                  <CardTitle className="text-sm font-medium">Próximo Pagamento</CardTitle>
                  <Calendar className="h-4 w-4 text-muted-foreground" />
                </CardHeader>
                <CardContent>
                  <div className="text-sm font-bold mb-1" data-testid="text-next-payment">
                    {stats.nextPaymentDate || "Não informado"}
                  </div>
                  <Badge 
                    variant={stats.paymentStatus === 'paid' ? 'default' : 'destructive'}
                    data-testid="badge-payment-status"
                  >
                    {stats.paymentStatus === 'paid' ? 'Em dia' : 'Pendente'}
                  </Badge>
                </CardContent>
              </Card>
            </div>
          )}

          <div className="grid gap-6 lg:grid-cols-2">
            {/* Upcoming Classes */}
            <Card>
              <CardHeader>
                <CardTitle>Próximas Aulas</CardTitle>
                <CardDescription>Suas aulas matriculadas esta semana</CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                {studentData?.enrollments?.filter(e => e.active).length === 0 ? (
                  <p className="text-muted-foreground text-center py-4">
                    Nenhuma matrícula ativa encontrada
                  </p>
                ) : (
                  studentData?.enrollments
                    ?.filter(e => e.active)
                    ?.slice(0, 3)
                    ?.map((enrollment) => (
                      <div 
                        key={enrollment.id} 
                        className="flex items-center space-x-4 p-3 rounded-lg hover:bg-muted/50 transition-colors"
                        data-testid={`upcoming-class-${enrollment.id}`}
                      >
                        <div className="flex-shrink-0">
                          <div className="w-12 h-12 bg-primary/10 rounded-lg flex items-center justify-center">
                            <Calendar className="h-6 w-6 text-primary" />
                          </div>
                        </div>
                        <div className="flex-1 min-w-0">
                          <p className="font-medium truncate" data-testid={`class-name-${enrollment.id}`}>
                            {enrollment.class.classType.name}
                          </p>
                          <p className="text-sm text-muted-foreground">
                            {enrollment.class.instructor.name}
                          </p>
                          <div className="flex items-center space-x-4 text-xs text-muted-foreground mt-1">
                            <span>{getDayName(enrollment.class.dayOfWeek)}</span>
                            <span className="flex items-center">
                              <Clock className="h-3 w-3 mr-1" />
                              {enrollment.class.startTime} - {enrollment.class.endTime}
                            </span>
                          </div>
                        </div>
                      </div>
                    ))
                )}
              </CardContent>
            </Card>

            {/* Recent Attendance */}
            <Card>
              <CardHeader>
                <CardTitle>Presenças Recentes</CardTitle>
                <CardDescription>Seu histórico de frequência</CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                {!studentData?.attendance || studentData.attendance.length === 0 ? (
                  <p className="text-muted-foreground text-center py-4">
                    Nenhum registro de presença encontrado
                  </p>
                ) : (
                  studentData.attendance
                    .slice(0, 5)
                    .map((record, index) => (
                      <div 
                        key={record.id} 
                        className="flex items-center space-x-4 p-3 rounded-lg"
                        data-testid={`attendance-record-${index}`}
                      >
                        <div className="flex-shrink-0">
                          {record.status === 'presente' ? (
                            <CheckCircle2 className="h-6 w-6 text-green-600" />
                          ) : (
                            <div className="h-6 w-6 rounded-full border-2 border-muted-foreground" />
                          )}
                        </div>
                        <div className="flex-1 min-w-0">
                          <p className="font-medium truncate" data-testid={`attendance-class-${index}`}>
                            {record.class.classType.name}
                          </p>
                          <p className="text-sm text-muted-foreground">
                            {record.class.instructor.name} • {formatDate(record.date)}
                          </p>
                          {record.notes && (
                            <p className="text-xs text-orange-600 mt-1">{record.notes}</p>
                          )}
                        </div>
                        <div className="flex-shrink-0">
                          <Badge 
                            variant={record.status === 'presente' ? "default" : "secondary"}
                            className={record.status === 'presente' ? "text-green-600" : "text-muted-foreground"}
                            data-testid={`attendance-status-${index}`}
                          >
                            {record.status === 'presente' ? 'Presente' : 
                             record.status === 'falta' ? 'Falta' : 'Justificado'}
                          </Badge>
                        </div>
                      </div>
                    ))
                )}
              </CardContent>
            </Card>
          </div>

          {/* Membership Info */}
          {studentData?.enrollments && studentData.enrollments.length > 0 && (
            <Card>
              <CardHeader>
                <CardTitle>Informações da Matrícula</CardTitle>
                <CardDescription>Detalhes da sua mensalidade atual</CardDescription>
              </CardHeader>
              <CardContent className="grid gap-4 md:grid-cols-3">
                <div>
                  <p className="text-sm font-medium text-muted-foreground">Plano</p>
                  <p className="text-lg font-semibold" data-testid="text-membership-plan">
                    {studentData.enrollments[0].membershipPlan.name}
                  </p>
                </div>
                <div>
                  <p className="text-sm font-medium text-muted-foreground">Início da Matrícula</p>
                  <p className="text-lg font-semibold" data-testid="text-enrollment-start">
                    {formatDate(studentData.enrollments[0].startDate)}
                  </p>
                </div>
                <div>
                  <p className="text-sm font-medium text-muted-foreground">Aulas por Semana</p>
                  <p className="text-lg font-semibold" data-testid="text-classes-per-week">
                    {studentData.enrollments[0].membershipPlan.classesPerWeek || 'Ilimitado'}
                  </p>
                </div>
              </CardContent>
            </Card>
          )}
        </div>
      </main>
    </div>
  );
}

function PortalHeader({ user, onLogout }: { user: any; onLogout: () => void }) {
  return (
    <header className="border-b bg-background/95 backdrop-blur-sm">
      <div className="container max-w-6xl mx-auto flex items-center justify-between p-4">
        <div className="flex items-center space-x-4">
          <div className="bg-primary/10 p-2 rounded-lg">
            <Award className="h-6 w-6 text-primary" />
          </div>
          <div>
            <h2 className="font-semibold">{user?.academy?.name || 'Portal do Aluno'}</h2>
            <p className="text-sm text-muted-foreground">{user?.name}</p>
          </div>
        </div>
        <Button 
          variant="outline" 
          size="sm" 
          onClick={onLogout}
          data-testid="button-logout"
        >
          <LogOut className="mr-2 h-4 w-4" />
          Sair
        </Button>
      </div>
    </header>
