import { useState } from "react";
import { useMutation, useQueryClient } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Alert, AlertDescription } from "@/components/ui/alert";
import { Loader2, Lock, Eye, EyeOff } from "lucide-react";
import { apiClient } from "@/lib/api";
import { useToast } from "@/hooks/use-toast";
import { useAuth } from "@/hooks/useAuth";

interface ChangePasswordModalProps {
  isOpen: boolean;
  onSuccess: () => void;
}

export function ChangePasswordModal({ isOpen, onSuccess }: ChangePasswordModalProps) {
  const [formData, setFormData] = useState({
    currentPassword: "",
    newPassword: "",
    confirmPassword: "",
  });
  const [showPasswords, setShowPasswords] = useState({
    current: false,
    new: false,
    confirm: false,
  });
  const [error, setError] = useState("");
  const { toast } = useToast();
  const { user: authUser, updateUser } = useAuth();
  const queryClient = useQueryClient();

  const changePasswordMutation = useMutation({
    mutationFn: (passwordData: typeof formData) => apiClient.changePassword(passwordData),
    onSuccess: async () => {
      toast({
        title: "Senha Alterada!",
        description: "Sua senha foi alterada com sucesso. Agora você pode acessar o portal.",
      });

      // Clear form
      setFormData({
        currentPassword: "",
        newPassword: "",
        confirmPassword: "",
      });
      setError("");

      // Update firstAccess flag in user state and localStorage
      updateUser({ firstAccess: false });

      // Invalidate queries to refresh data
      queryClient.invalidateQueries({ queryKey: ['/api/auth/me'] });

      onSuccess();
    },
    onError: (error: Error) => {
      setError(error.message);
      toast({
        title: "Erro ao Alterar Senha",
        description: error.message,
        variant: "destructive",
      });
    },
  });

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError("");

    // Validation
    if (!formData.currentPassword || !formData.newPassword || !formData.confirmPassword) {
      setError("Por favor, preencha todos os campos");
      return;
    }

    if (formData.newPassword.length < 6) {
      setError("A nova senha deve ter pelo menos 6 caracteres");
      return;
    }

    if (formData.newPassword !== formData.confirmPassword) {
      setError("As senhas não coincidem");
      return;
    }

    if (formData.currentPassword === formData.newPassword) {
      setError("A nova senha deve ser diferente da senha atual");
      return;
    }

    changePasswordMutation.mutate(formData);
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
    // Clear error when user starts typing
    if (error) setError("");
  };

  const togglePasswordVisibility = (field: 'current' | 'new' | 'confirm') => {
    setShowPasswords(prev => ({
      ...prev,
      [field]: !prev[field]
    }));
  };

  return (
    <Dialog open={isOpen} onOpenChange={() => {}}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <div className="flex items-center justify-center mb-4">
            <div className="bg-primary/10 p-3 rounded-full">
              <Lock className="h-8 w-8 text-primary" />
            </div>
          </div>
          <DialogTitle className="text-center text-xl">
            Primeiro Acesso
          </DialogTitle>
          <DialogDescription className="text-center">
            Por segurança, você precisa alterar sua senha no primeiro acesso.
            Escolha uma senha segura e fácil de lembrar.
          </DialogDescription>
        </DialogHeader>

        <form onSubmit={handleSubmit} className="space-y-4">
          {error && (
            <Alert variant="destructive">
              <AlertDescription>{error}</AlertDescription>
            </Alert>
          )}

          {/* Current Password */}
          <div className="space-y-2">
            <Label htmlFor="currentPassword">Senha Atual</Label>
            <div className="relative">
              <Input
                id="currentPassword"
                name="currentPassword"
                type={showPasswords.current ? "text" : "password"}
                placeholder="Digite sua senha atual"
                value={formData.currentPassword}
                onChange={handleInputChange}
                disabled={changePasswordMutation.isPending}
                data-testid="input-current-password"
                required
              />
              <Button
                type="button"
                variant="ghost"
                size="sm"
                className="absolute right-0 top-0 h-full px-3 py-2 hover:bg-transparent"
                onClick={() => togglePasswordVisibility('current')}
                disabled={changePasswordMutation.isPending}
              >
                {showPasswords.current ? (
                  <EyeOff className="h-4 w-4" />
                ) : (
                  <Eye className="h-4 w-4" />
                )}
              </Button>
            </div>
          </div>

          {/* New Password */}
          <div className="space-y-2">
            <Label htmlFor="newPassword">Nova Senha</Label>
            <div className="relative">
              <Input
                id="newPassword"
                name="newPassword"
                type={showPasswords.new ? "text" : "password"}
                placeholder="Digite sua nova senha (min. 6 caracteres)"
                value={formData.newPassword}
                onChange={handleInputChange}
                disabled={changePasswordMutation.isPending}
                data-testid="input-new-password"
                required
              />
              <Button
                type="button"
                variant="ghost"
                size="sm"
                className="absolute right-0 top-0 h-full px-3 py-2 hover:bg-transparent"
                onClick={() => togglePasswordVisibility('new')}
                disabled={changePasswordMutation.isPending}
              >
                {showPasswords.new ? (
                  <EyeOff className="h-4 w-4" />
                ) : (
                  <Eye className="h-4 w-4" />
                )}
              </Button>
            </div>
          </div>

          {/* Confirm Password */}
          <div className="space-y-2">
            <Label htmlFor="confirmPassword">Confirmar Nova Senha</Label>
            <div className="relative">
              <Input
                id="confirmPassword"
                name="confirmPassword"
                type={showPasswords.confirm ? "text" : "password"}
                placeholder="Digite novamente sua nova senha"
                value={formData.confirmPassword}
                onChange={handleInputChange}
                disabled={changePasswordMutation.isPending}
                data-testid="input-confirm-password"
                required
              />
              <Button
                type="button"
                variant="ghost"
                size="sm"
                className="absolute right-0 top-0 h-full px-3 py-2 hover:bg-transparent"
                onClick={() => togglePasswordVisibility('confirm')}
                disabled={changePasswordMutation.isPending}
              >
                {showPasswords.confirm ? (
                  <EyeOff className="h-4 w-4" />
                ) : (
                  <Eye className="h-4 w-4" />
                )}
              </Button>
            </div>
          </div>

          {/* Password Requirements */}
          <div className="bg-muted/30 p-3 rounded-lg">
            <p className="text-sm font-medium mb-2">Requisitos da senha:</p>
            <ul className="text-xs text-muted-foreground space-y-1">
              <li>• Mínimo de 6 caracteres</li>
              <li>• Diferente da senha atual</li>
              <li>• Use uma combinação de letras e números</li>
            </ul>
          </div>

          <Button
            type="submit"
            className="w-full"
            disabled={
              changePasswordMutation.isPending || 
              !formData.currentPassword || 
              !formData.newPassword || 
              !formData.confirmPassword
            }
            data-testid="button-change-password"
          >
            {changePasswordMutation.isPending ? (
              <>
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                Alterando Senha...
              </>
            ) : (
              <>
                <Lock className="mr-2 h-4 w-4" />
                Alterar Senha
              </>
            )}
          </Button>
        </form>

        <div className="text-center">
          <p className="text-xs text-muted-foreground">
            Esta alteração é obrigatória por questões de segurança.
            Entre em contato com a academia se tiver problemas.
          </p>
        </div>
      </DialogContent>
    </Dialog>
  );
}

client/src/components/FirstAccessGuard.t.content:
import { useEffect } from "react";
import { useAuth } from "@/hooks/useAuth";
import { useLocation } from "wouter";

interface FirstAccessGuardProps {
  children: React.ReactNode;
}

export function FirstAccessGuard({ children }: FirstAccessGuardProps) {
  const { user, isAuthenticated } = useAuth();
  const [location, setLocation] = useLocation();

  useEffect(() => {
    // Only apply first access guard for authenticated students
    if (isAuthenticated && user?.role === 'ALUNO' && user.firstAccess) {
      // If user is on a portal route (except login), redirect to login to show password change modal
      if (location.startsWith('/portal/') && location !== '/portal/login') {
        setLocation('/portal/login');
      }
    }
  }, [isAuthenticated, user, location, setLocation]);

  // If this is a student on first access and trying to access portal routes (except login),
  // don't render the protected content
  if (
    isAuthenticated && 
    user?.role === 'ALUNO' && 
    user.firstAccess && 
    location.startsWith('/portal/') && 
    location !== '/portal/login'
  ) {
    // Return loading state while redirecting
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary mx-auto mb-4"></div>
          <p>Redirecionando para alteração de senha...</p>
        </div>
      </div>
    );
  }

  return <>{children}</>;
}

client/src/pages/SuperAdminPlanos.tsx.content:
import { useState, useEffect } from "react";
import { useQuery, useMutation } from "@tanstack/react-query";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Switch } from "@/components/ui/switch";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { 
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { 
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { 
  CreditCard, 
  Users, 
  Plus,
  Edit,
  Calendar,
  DollarSign
} from "lucide-react";
import { Link, useLocation } from "wouter";
import { useToast } from "@/hooks/use-toast";
import { apiRequest, queryClient } from "@/lib/queryClient";
import type { Plano, InsertPlano } from "@shared/schema";
import { insertPlanoSchema } from "@shared/schema";

export default function SuperAdminPlanos() {
  const [isCreateDialogOpen, setIsCreateDialogOpen] = useState(false);
  const [editingPlano, setEditingPlano] = useState<Plano | null>(null);
  const [location, setLocation] = useLocation();

  const form = useForm<InsertPlano>({
    resolver: zodResolver(insertPlanoSchema),
    defaultValues: {
      nome: "",
      limiteAlunos: 50,
      precoMensal: 5000, // in cents
      ativo: true
    }
  });

  // Handle deep-link create flow
  useEffect(() => {
    if (location === '/superadmin/planos/novo') {
      setIsCreateDialogOpen(true);
    }
  }, [location]);

  // Handle dialog close navigation
  const handleCreateDialogClose = (open: boolean) => {
    setIsCreateDialogOpen(open);
    if (!open && location === '/superadmin/planos/novo') {
      setLocation('/superadmin/planos');
    }
  };

  const { toast } = useToast();

  const { data: planos, isLoading } = useQuery<Plano[]>({
    queryKey: ["/api/superadmin/planos"],
  });

  const createPlanoMutation = useMutation({
    mutationFn: (planoData: InsertPlano) =>
      apiRequest("POST", "/api/superadmin/planos", planoData),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/superadmin/planos"] });
      setIsCreateDialogOpen(false);
      form.reset();
      toast({
        title: "Plano criado com sucesso",
        description: "O novo plano foi adicionado à plataforma.",
      });
    },
    onError: () => {
      toast({
        title: "Erro ao criar plano",
        description: "Verifique os dados e tente novamente.",
        variant: "destructive",
      });
    },
  });

  const onSubmit = (data: InsertPlano) => {
    // Ensure precoMensal is converted to cents if needed
    const submitData = {
      ...data,
      precoMensal: typeof data.precoMensal === 'string' 
        ? Math.round(parseFloat(data.precoMensal) * 100)
        : data.precoMensal
    };
    createPlanoMutation.mutate(submitData);
  };

  const updatePlanoMutation = useMutation({
    mutationFn: ({ id, ...data }: { id: string } & Partial<InsertPlano>) =>
      apiRequest("PATCH", `/api/superadmin/planos/${id}`, data),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/superadmin/planos"] });
      setEditingPlano(null);
      toast({
        title: "Plano atualizado",
        description: "As alterações foram salvas com sucesso.",
      });
    },
    onError: () => {
      toast({
        title: "Erro ao atualizar plano",
        description: "Verifique os dados e tente novamente.",
        variant: "destructive",
      });
    },
  });

  const handleCreatePlano = () => {
    form.handleSubmit(onSubmit)();
  };

  const handleUpdatePlano = () => {
    if (!editingPlano) return;
    const { id, ...planoData } = editingPlano;
    updatePlanoMutation.mutate({ id, ...planoData });
  };

  const formatPrice = (priceInCents: number) => {
    return new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL'
    }).format(priceInCents / 100);
  };

  if (isLoading) {
    return (
      <div className="space-y-6">
        <div>
          <h1 className="text-3xl font-bold">Gerenciar Planos</h1>
          <p className="text-muted-foreground mt-2">
            Criar e gerenciar planos de assinatura da plataforma
          </p>
        </div>
        <div className="animate-pulse space-y-4">
          <div className="h-32 bg-muted rounded"></div>
          <div className="h-64 bg-muted rounded"></div>
        </div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold">Gerenciar Planos</h1>
          <p className="text-muted-foreground mt-2">
            Criar e gerenciar planos de assinatura da plataforma SaaS
          </p>
        </div>
        <div className="flex gap-2">
          <Button asChild variant="outline">
            <Link href="/superadmin/dashboard" data-testid="button-back-dashboard">
              Voltar ao Dashboard
            </Link>
          </Button>
          <Dialog open={isCreateDialogOpen} onOpenChange={handleCreateDialogClose}>
            <DialogTrigger asChild>
              <Button data-testid="button-create-plan">
                <Plus className="h-4 w-4 mr-2" />
                Novo Plano
              </Button>
            </DialogTrigger>
            <DialogContent className="sm:max-w-[425px]">
              <DialogHeader>
                <DialogTitle>Criar Novo Plano</DialogTitle>
                <DialogDescription>
                  Configure um novo plano de assinatura para a plataforma
                </DialogDescription>
              </DialogHeader>
              <div className="grid gap-4 py-4">
                <div className="grid gap-2">
                  <Label htmlFor="nome">Nome do Plano</Label>
                  <Input
                    id="nome"
                    {...form.register("nome")}
                    placeholder="Ex: Faixa Branca"
                    data-testid="input-plan-name"
                  />
                </div>
                <div className="grid gap-2">
                  <Label htmlFor="limiteAlunos">Limite de Alunos</Label>
                  <Input
                    id="limiteAlunos"
                    type="number"
                    {...form.register("limiteAlunos", { valueAsNumber: true })}
                    data-testid="input-student-limit"
                  />
                </div>
                <div className="grid gap-2">
                  <Label htmlFor="precoMensal">Preço Mensal (R$)</Label>
                  <Input
                    id="precoMensal"
                    type="number"
                    step="0.01"
                    {...form.register("precoMensal", { 
                      setValueAs: (value) => Math.round(parseFloat(value) * 100)
                    })}
                    data-testid="input-monthly-price"
                  />
                </div>
                <div className="flex items-center space-x-2">
                  <Switch
                    id="ativo"
                    {...form.register("ativo")}
                    data-testid="switch-plan-active"
                  />
                  <Label htmlFor="ativo">Plano ativo</Label>
                </div>
              </div>
              <DialogFooter>
                <Button onClick={handleCreatePlano} disabled={createPlanoMutation.isPending}>
                  {createPlanoMutation.isPending ? "Criando..." : "Criar Plano"}
                </Button>
              </DialogFooter>
            </DialogContent>
          </Dialog>
        </div>
      </div>

      {/* Stats Cards */}
      <div className="grid gap-4 md:grid-cols-3">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Total de Planos</CardTitle>
            <CreditCard className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold" data-testid="total-plans">
              {planos?.length || 0}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Planos Ativos</CardTitle>
            <Users className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {planos?.filter(p => p.ativo).length || 0}
            </div>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Preço Médio</CardTitle>
            <DollarSign className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {planos && planos.length > 0
                ? formatPrice(planos.reduce((sum, p) => sum + p.precoMensal, 0) / planos.length)
                : 'R$ 0,00'
              }
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Plans Table */}
      <Card>
        <CardHeader>
          <CardTitle>Lista de Planos</CardTitle>
          <CardDescription>
            Gerencie os planos de assinatura disponíveis na plataforma
          </CardDescription>
        </CardHeader>
        <CardContent>
          <Table>
            <TableHeader>
              <TableRow>
                <TableHead>Nome</TableHead>
                <TableHead>Limite de Alunos</TableHead>
                <TableHead>Preço Mensal</TableHead>
                <TableHead>Status</TableHead>
                <TableHead>Criado em</TableHead>
                <TableHead className="text-right">Ações</TableHead>
              </TableRow>
            </TableHeader>
            <TableBody>
              {planos?.map((plano) => (
                <TableRow key={plano.id} data-testid={`row-plan-${plano.id}`}>
                  <TableCell className="font-medium">{plano.nome}</TableCell>
                  <TableCell>
                    <div className="flex items-center gap-1">
                      <Users className="h-3 w-3" />
                      {plano.limiteAlunos}
                    </div>
                  </TableCell>
                  <TableCell className="font-mono">
                    {formatPrice(plano.precoMensal)}
                  </TableCell>
                  <TableCell>
                    <Badge 
                      variant={plano.ativo ? "default" : "secondary"}
                      className={plano.ativo 
                        ? "bg-green-100 text-green-800 dark:bg-green-900 dark:text-green-200" 
                        : ""
                      }
                    >
                      {plano.ativo ? "Ativo" : "Inativo"}
                    </Badge>
                  </TableCell>
                  <TableCell>
                    <div className="flex items-center gap-1 text-sm">
                      <Calendar className="h-3 w-3" />
                      {plano.createdAt ? new Date(plano.createdAt).toLocaleDateString('pt-BR') : 'N/A'}
                    </div>
                  </TableCell>
                  <TableCell className="text-right">
                    <Button 
                      variant="outline" 
                      size="sm"
                      onClick={() => setEditingPlano(plano)}
                      data-testid={`button-edit-plan-${plano.id}`}
                    >
                      <Edit className="h-4 w-4 mr-2" />
                      Editar
                    </Button>
                  </TableCell>
                </TableRow>
              ))}
              {(!planos || planos.length === 0) && (
                <TableRow>
                  <TableCell colSpan={6} className="text-center py-8">
                    <div className="flex flex-col items-center gap-2">
                      <CreditCard className="h-8 w-8 text-muted-foreground" />
                      <div className="text-sm text-muted-foreground">
                        Nenhum plano cadastrado
                      </div>
                    </div>
                  </TableCell>
                </TableRow>
              )}
            </TableBody>
          </Table>
        </CardContent>
      </Card>

      {/* Edit Plan Dialog */}
      {editingPlano && (
        <Dialog open={!!editingPlano} onOpenChange={() => setEditingPlano(null)}>
          <DialogContent className="sm:max-w-[425px]">
            <DialogHeader>
              <DialogTitle>Editar Plano</DialogTitle>
              <DialogDescription>
                Modifique as configurações do plano {editingPlano.nome}
              </DialogDescription>
            </DialogHeader>
            <div className="grid gap-4 py-4">
              <div className="grid gap-2">
                <Label htmlFor="edit-nome">Nome do Plano</Label>
                <Input
                  id="edit-nome"
                  value={editingPlano.nome}
                  onChange={(e) => setEditingPlano({ ...editingPlano, nome: e.target.value })}
                />
              </div>
              <div className="grid gap-2">
                <Label htmlFor="edit-limiteAlunos">Limite de Alunos</Label>
                <Input
                  id="edit-limiteAlunos"
                  type="number"
                  value={editingPlano.limiteAlunos}
                  onChange={(e) => setEditingPlano({ ...editingPlano, limiteAlunos: parseInt(e.target.value) })}
                />
              </div>
              <div className="grid gap-2">
                <Label htmlFor="edit-precoMensal">Preço Mensal (R$)</Label>
                <Input
                  id="edit-precoMensal"
                  type="number"
                  step="0.01"
                  value={editingPlano.precoMensal / 100}
                  onChange={(e) => setEditingPlano({ ...editingPlano, precoMensal: Math.round(parseFloat(e.target.value) * 100) })}
                />
              </div>
              <div className="flex items-center space-x-2">
                <Switch
                  id="edit-ativo"
                  checked={editingPlano.ativo ?? false}
                  onCheckedChange={(checked) => setEditingPlano({ ...editingPlano, ativo: checked })}
                />
                <Label htmlFor="edit-ativo">Plano ativo</Label>
              </div>
            </div>
            <DialogFooter>
              <Button onClick={handleUpdatePlano} disabled={updatePlanoMutation.isPending}>
                {updatePlanoMutation.isPending ? "Salvando..." : "Salvar Alterações"}
              </Button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      )}
    </div>
  );
}

server/seeds.ts.content:
import { Pool, neonConfig } from '@neondatabase/serverless';
import { drizzle } from 'drizzle-orm/neon-serverless';
import ws from "ws";
import bcrypt from 'bcryptjs';
import { planos, users } from "@shared/schema";
import type { InsertPlano, InsertUser } from "@shared/schema";
import { eq } from 'drizzle-orm';

// Configure WebSocket (same as main app)
neonConfig.webSocketConstructor = ws;

if (!process.env.DATABASE_URL) {
  throw new Error("DATABASE_URL not found");
}

const pool = new Pool({ connectionString: process.env.DATABASE_URL });
const db = drizzle({ client: pool });

const initialPlanos: InsertPlano[] = [
  {
    nome: "Beta Gratuito",
    limiteAlunos: 10,
    precoMensal: 0, // Free plan
    ativo: true
  },
  {
    nome: "Básico",
    limiteAlunos: 50,
    precoMensal: 4900, // R$ 49,00 in cents
    ativo: true
  },
  {
    nome: "Profissional",
    limiteAlunos: 200,
    precoMensal: 9900, // R$ 99,00 in cents
    ativo: true
  },
  {
    nome: "Enterprise",
    limiteAlunos: 500,
    precoMensal: 19900, // R$ 199,00 in cents
    ativo: true
  }
];

// Bootstrap SUPER_ADMIN user credentials (can be overridden via env vars)
const BOOTSTRAP_ADMIN = {
  email: process.env.SA_EMAIL || "superadmin@centrodelutas.com",
  password: process.env.SA_PASSWORD || "SuperAdmin123!",
  name: "Super Administrador"
};

async function seedSuperAdmin() {
  try {
    console.log("👤 Verificando usuário SUPER_ADMIN...");

    // Check if SUPER_ADMIN already exists
    const existingSuperAdmin = await db.select()
      .from(users)
      .where(eq(users.role, 'SUPER_ADMIN'));

    if (existingSuperAdmin.length > 0) {
      console.log(`⚠️  Usuário SUPER_ADMIN já existe (${existingSuperAdmin[0].email}). Pulando criação.`);
      return;
    }

    // Hash the password
    const hashedPassword = await bcrypt.hash(BOOTSTRAP_ADMIN.password, 10);

    // Create SUPER_ADMIN user
    const superAdminUser: InsertUser = {
      email: BOOTSTRAP_ADMIN.email,
      password: hashedPassword,
      name: BOOTSTRAP_ADMIN.name,
      role: 'SUPER_ADMIN',
      academyId: null, // SUPER_ADMIN has no academy restriction
      active: true,
      firstAccess: false // No password change required for bootstrap user
    };

    const [insertedUser] = await db.insert(users).values(superAdminUser).returning();

    console.log("✅ Usuário SUPER_ADMIN criado com sucesso:");
    console.log(`   • Email: ${insertedUser.email}`);
    console.log(`   • Nome: ${insertedUser.name}`);
    console.log(`   • Senha: ${BOOTSTRAP_ADMIN.password}`);

  } catch (error) {
    console.error("❌ Erro ao criar usuário SUPER_ADMIN:", error);
    throw error;
  }
}

async function seedPlanos() {
  try {
    console.log("🌱 Verificando planos...");

    // Check if plans already exist
    const existingPlanos = await db.select().from(planos);

    if (existingPlanos.length > 0) {
      console.log(`⚠️  ${existingPlanos.length} planos já existem no banco. Pulando seeding.`);
      return;
    }

    // Insert initial plans
    const insertedPlanos = await db.insert(planos).values(initialPlanos).returning();

    console.log("✅ Planos criados com sucesso:");
    insertedPlanos.forEach(plano => {
      const preco = plano.precoMensal === 0 ? "Gratuito" : `R$ ${(plano.precoMensal / 100).toFixed(2)}`;
      console.log(`   • ${plano.nome}: ${plano.limiteAlunos} alunos - ${preco}/mês`);
    });

  } catch (error) {
    console.error("❌ Erro ao fazer seeding dos planos:", error);
    throw error;
  }
}

async function seedDatabase() {
  try {
    console.log("🚀 Iniciando seeding completo do banco de dados...");

    await seedSuperAdmin();
    await seedPlanos();

    console.log("🎉 Seeding completo concluído com sucesso!");

  } catch (error) {
    console.error("💥 Seeding falhou:", error);
    throw error;
  } finally {
    await pool.end();
  }
}

// Run seeding if called directly
if (import.meta.url === `file://${process.argv[1]}`) {
  seedDatabase()
    .then(() => {
      process.exit(0);
    })
    .catch((error) => {
      console.error("💥 Seeding falhou:", error);
      process.exit(1);
    });
}

export { seedDatabase, seedPlanos, seedSuperAdmin };

